package.preload["dtrmflickr.oauth"] = function(...)
-- oauth.lua — pure-Lua OAuth 1.0a (HMAC-SHA1) signing for Flickr.
--
-- No external dependencies. Uses Lua 5.4 native integer + bitwise operators
-- (darktable embeds Lua 5.4). This is the piece darktable's Lua gives us no
-- help with: there is no built-in crypto/hash/base64, and LuaSec's high-level
-- API does not expose HMAC. So we implement SHA-1 / HMAC-SHA1 / Base64 /
-- RFC-3986 percent-encoding here, and the OAuth signature on top.

local M = {}

----------------------------------------------------------------------
-- SHA-1 -> raw 20-byte binary string
----------------------------------------------------------------------
local function rol(x, n)
  x = x & 0xFFFFFFFF
  return ((x << n) | (x >> (32 - n))) & 0xFFFFFFFF
end

local function sha1_bin(msg)
  local h0, h1, h2, h3, h4 =
    0x67452301, 0xEFCDAB89, 0x98BADCFE, 0x10325476, 0xC3D2E1F0
  local ml = #msg * 8

  -- pad: 0x80, then 0x00 until length % 64 == 56, then 64-bit BE bit length
  msg = msg .. "\128"
  while (#msg % 64) ~= 56 do msg = msg .. "\0" end
  local lenbytes = {}
  for i = 7, 0, -1 do lenbytes[#lenbytes + 1] = string.char((ml >> (i * 8)) & 0xFF) end
  msg = msg .. table.concat(lenbytes)

  for chunk = 1, #msg, 64 do
    local w = {}
    for i = 0, 15 do
      local b1, b2, b3, b4 = string.byte(msg, chunk + i * 4, chunk + i * 4 + 3)
      w[i] = ((b1 << 24) | (b2 << 16) | (b3 << 8) | b4) & 0xFFFFFFFF
    end
    for i = 16, 79 do
      w[i] = rol(w[i - 3] ~ w[i - 8] ~ w[i - 14] ~ w[i - 16], 1)
    end

    local a, b, c, d, e = h0, h1, h2, h3, h4
    for i = 0, 79 do
      local f, k
      if i < 20 then
        f = (b & c) | ((~b & 0xFFFFFFFF) & d); k = 0x5A827999
      elseif i < 40 then
        f = b ~ c ~ d; k = 0x6ED9EBA1
      elseif i < 60 then
        f = (b & c) | (b & d) | (c & d); k = 0x8F1BBCDC
      else
        f = b ~ c ~ d; k = 0xCA62C1D6
      end
      local tmp = (rol(a, 5) + f + e + k + w[i]) & 0xFFFFFFFF
      e = d; d = c; c = rol(b, 30); b = a; a = tmp
    end

    h0 = (h0 + a) & 0xFFFFFFFF; h1 = (h1 + b) & 0xFFFFFFFF
    h2 = (h2 + c) & 0xFFFFFFFF; h3 = (h3 + d) & 0xFFFFFFFF
    h4 = (h4 + e) & 0xFFFFFFFF
  end

  local out = {}
  for _, h in ipairs({ h0, h1, h2, h3, h4 }) do
    out[#out + 1] = string.char((h >> 24) & 0xFF, (h >> 16) & 0xFF, (h >> 8) & 0xFF, h & 0xFF)
  end
  return table.concat(out)
end

----------------------------------------------------------------------
-- HMAC-SHA1 -> raw 20-byte binary string
----------------------------------------------------------------------
local function hmac_sha1_bin(key, msg)
  if #key > 64 then key = sha1_bin(key) end
  key = key .. string.rep("\0", 64 - #key)
  local o, i = {}, {}
  for n = 1, 64 do
    local b = string.byte(key, n)
    o[n] = string.char(b ~ 0x5C)
    i[n] = string.char(b ~ 0x36)
  end
  return sha1_bin(table.concat(o) .. sha1_bin(table.concat(i) .. msg))
end

----------------------------------------------------------------------
-- Base64 (standard alphabet, padded)
----------------------------------------------------------------------
local B64 = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local function base64(data)
  local out = {}
  for i = 1, #data, 3 do
    local b1 = string.byte(data, i)
    local b2 = string.byte(data, i + 1)
    local b3 = string.byte(data, i + 2)
    local n24 = (b1 << 16) | ((b2 or 0) << 8) | (b3 or 0)
    local c1 = (n24 >> 18) & 63
    local c2 = (n24 >> 12) & 63
    local c3 = (n24 >> 6) & 63
    local c4 = n24 & 63
    out[#out + 1] = B64:sub(c1 + 1, c1 + 1)
    out[#out + 1] = B64:sub(c2 + 1, c2 + 1)
    out[#out + 1] = b2 and B64:sub(c3 + 1, c3 + 1) or "="
    out[#out + 1] = b3 and B64:sub(c4 + 1, c4 + 1) or "="
  end
  return table.concat(out)
end

----------------------------------------------------------------------
-- RFC 3986 percent-encoding (OAuth-correct: only A-Z a-z 0-9 - . _ ~ raw)
----------------------------------------------------------------------
local function encode(s)
  return (tostring(s):gsub("[^%w%-%._~]", function(c)
    return string.format("%%%02X", string.byte(c))
  end))
end

----------------------------------------------------------------------
-- OAuth 1.0a signature.
--   params: table of {name = value} (all oauth_* + method params, EXCLUDING
--           oauth_signature and excluding the binary "photo" on upload).
-- returns: signature (base64), base_string (for debugging)
----------------------------------------------------------------------
local function signature(method, base_url, params, consumer_secret, token_secret)
  local keys = {}
  for k in pairs(params) do keys[#keys + 1] = k end
  table.sort(keys, function(x, y)
    local ex, ey = encode(x), encode(y)
    if ex == ey then return encode(params[x]) < encode(params[y]) end
    return ex < ey
  end)

  local parts = {}
  for _, k in ipairs(keys) do
    parts[#parts + 1] = encode(k) .. "=" .. encode(params[k])
  end
  local param_str = table.concat(parts, "&")

  local base = method:upper() .. "&" .. encode(base_url) .. "&" .. encode(param_str)
  local key = encode(consumer_secret) .. "&" .. encode(token_secret or "")
  return base64(hmac_sha1_bin(key, base)), base
end

----------------------------------------------------------------------
-- helpers / exports
----------------------------------------------------------------------
local function tohex(s)
  return (s:gsub(".", function(c) return string.format("%02x", string.byte(c)) end))
end

M.encode        = encode
M.base64        = base64
M.sha1_bin      = sha1_bin
M.sha1_hex      = function(s) return tohex(sha1_bin(s)) end
M.hmac_sha1_bin = hmac_sha1_bin
M.hmac_sha1_hex = function(k, m) return tohex(hmac_sha1_bin(k, m)) end
M.signature     = signature

return M
end

package.preload["dtrmflickr.http"] = function(...)
-- http.lua — minimal HTTP transport for dtrmflickr.
--
-- Step-0 decision: curl-primary on Unix-like systems (it is the only client
-- that "just worked" across platforms without a build step; LuaSec needs a C
-- toolchain). On Windows, REST GET/POST prefer an optional in-process WinHTTP
-- module. If that DLL is not installed or cannot be loaded, manual Windows
-- REST calls fall back to a hidden WScript/MSXML helper.
-- Uploads still fall back to curl because building multipart bodies in pure Lua
-- is much more fragile than curl's battle-tested form encoder.
--
-- NOTE: io.popen blocks until the command finishes. OAuth token calls are tiny
-- and fast, so that is fine here. The (potentially long) photo upload in step 3
-- will run inside a darktable job/coroutine instead of blocking the UI.

local M = {}
local temp_counter = 0
local temp_token = tostring({}):gsub("%W", "")
local native_http_ok, native_http = false, nil
local native_http_error = nil
local run

local function is_windows()
  return package.config:sub(1, 1) == "\\"
end

local function path_join(a, b)
  local sep = is_windows() and "\\" or "/"
  return tostring(a or ""):gsub("[/\\]+$", "") .. sep .. tostring(b or "")
end

local function try_native_require(name)
  local ok, mod = pcall(require, name)
  if ok and mod and mod.request then return true, mod end
  return false, mod
end

local function try_native_loadlib(path, symbol)
  if not package.loadlib then return false, "package.loadlib unavailable" end
  local loader, err = package.loadlib(path, symbol)
  if not loader then return false, err end
  local ok, mod = pcall(loader)
  if ok and mod and mod.request then return true, mod end
  return false, mod
end

local function script_dir()
  local info = debug and debug.getinfo and debug.getinfo(1, "S") or nil
  local source = info and info.source or ""
  local path = source:match("^@(.+)$")
  if not path then return nil end
  return path:match("^(.*)[/\\][^/\\]+$")
end

local function load_native_http()
  local errors = {}
  for _, name in ipairs({ "dtrmflickr.dtrmflickr_winhttp", "dtrmflickr_winhttp" }) do
    local ok, mod_or_err = try_native_require(name)
    if ok then return true, mod_or_err, "require " .. name end
    errors[#errors + 1] = name .. ": " .. tostring(mod_or_err)
  end

  if is_windows() then
    local paths = {}
    local dir = script_dir()
    if dir then paths[#paths + 1] = path_join(dir, "dtrmflickr_winhttp.dll") end
    local localappdata = os.getenv("LOCALAPPDATA")
    if localappdata then
      paths[#paths + 1] = path_join(path_join(path_join(path_join(localappdata, "darktable"), "lua"), "dtrmflickr"), "dtrmflickr_winhttp.dll")
    end
    for _, path in ipairs(paths) do
      local ok, mod_or_err = try_native_loadlib(path, "luaopen_dtrmflickr_winhttp")
      if ok then return true, mod_or_err, "loadlib " .. path end
      errors[#errors + 1] = path .. ": " .. tostring(mod_or_err)
    end
  end

  return false, nil, table.concat(errors, " | ")
end

native_http_ok, native_http, native_http_error = load_native_http()

-- shell-quote a single argument. POSIX shells still expand $, backticks, and
-- command substitutions inside double quotes, so use single quotes there.
local function shq(s)
  if not is_windows() then
    return "'" .. tostring(s):gsub("'", "'\\''") .. "'"
  end
  return '"' .. tostring(s):gsub('"', '\\"') .. '"'
end
M.shq = shq

local function curl_config_quote(s)
  return '"' .. tostring(s or "")
    :gsub("\\", "\\\\")
    :gsub('"', '\\"')
    :gsub("\r", "\\r")
    :gsub("\n", "\\n")
    .. '"'
end

local function temp_path(suffix)
  temp_counter = temp_counter + 1
  local dir = os.getenv("TEMP") or os.getenv("TMP") or "."
  local sep = is_windows() and "\\" or "/"
  return dir .. sep .. "dtrmflickr-" .. tostring(os.time()) .. "-" .. temp_token .. "-" .. tostring(temp_counter) .. suffix
end

local function read_file(path)
  local f = io.open(path, "rb")
  if not f then return nil end
  local body = f:read("*a")
  f:close()
  body = body and body:gsub("^\239\187\191", "") or body
  return body
end

local function write_file(path, body)
  local f = io.open(path, "wb")
  if not f then return nil end
  f:write(body)
  f:close()
  return true
end

local function run_curl_config(lines)
  local config_path = temp_path(".curl")
  if not write_file(config_path, table.concat(lines, "\n") .. "\n") then
    return nil, "could not write temporary curl config"
  end
  local out, err = run("curl --config " .. shq(config_path))
  os.remove(config_path)
  return out, err
end

local function vbs_quote(s)
  return '"' .. tostring(s):gsub('"', '""') .. '"'
end

local function launch_windows(command)
  return os.execute(command)
end

local function command_succeeded(ok, why, code)
  if ok == true or ok == 0 then return true end
  if type(ok) == "number" then return ok == 0 end
  return false, why, code
end

local function batch_escape(s)
  return tostring(s or ""):gsub("%%", "%%%%")
end

local function run_windows_hidden(cmd)
  local out_path = temp_path(".out")
  local err_path = temp_path(".err")
  local vbs_path = temp_path(".vbs")
  local bat_path

  local wrapped
  if tostring(cmd):match("^%s*curl%s") then
    wrapped = cmd .. " -o " .. shq(out_path) .. " --stderr " .. shq(err_path)
  else
    bat_path = temp_path(".bat")
    local bat = table.concat({
      "@echo off",
      batch_escape(cmd) .. ' > "' .. out_path .. '" 2> "' .. err_path .. '"',
      "exit /b %ERRORLEVEL%",
    }, "\r\n")
    if not write_file(bat_path, bat) then return nil, "could not write temporary command" end
    wrapped = 'cmd.exe /d /c ""' .. bat_path .. '""'
  end
  local script = table.concat({
    'Set shell = CreateObject("WScript.Shell")',
    'code = shell.Run(' .. vbs_quote(wrapped) .. ', 0, True)',
    'WScript.Quit code',
  }, "\r\n")
  if not write_file(vbs_path, script) then return nil, "could not write temporary script" end
  local ok, why, code = launch_windows("wscript.exe //B //Nologo " .. shq(vbs_path))
  local out = read_file(out_path) or ""
  local err = read_file(err_path) or ""
  os.remove(vbs_path)
  if bat_path then os.remove(bat_path) end
  os.remove(out_path)
  os.remove(err_path)
  if not command_succeeded(ok, why, code) then
    local detail = err ~= "" and err or out
    return nil, detail ~= "" and detail or ("command failed: " .. tostring(why or code or ok))
  end
  return out ~= "" and out or err
end

local function windows_http(method, url, body, content_type)
  local out_path = temp_path(".out")
  local err_path = temp_path(".err")
  local body_path = body ~= nil and temp_path(".body") or ""
  local vbs_path = temp_path(".vbs")

  if body ~= nil and not write_file(body_path, body) then
    return nil, "could not write temporary request body"
  end

  local script = table.concat({
    "On Error Resume Next",
    "Const adTypeText = 2",
    "Const adSaveCreateOverWrite = 2",
    "Function ReadUtf8(path)",
    "  Dim s",
    "  Set s = CreateObject(\"ADODB.Stream\")",
    "  s.Type = adTypeText",
    "  s.Charset = \"utf-8\"",
    "  s.Open",
    "  s.LoadFromFile path",
    "  ReadUtf8 = s.ReadText",
    "  s.Close",
    "End Function",
    "Sub WriteUtf8(path, text)",
    "  Dim s",
    "  Set s = CreateObject(\"ADODB.Stream\")",
    "  s.Type = adTypeText",
    "  s.Charset = \"utf-8\"",
    "  s.Open",
    "  s.WriteText text",
    "  s.SaveToFile path, adSaveCreateOverWrite",
    "  s.Close",
    "End Sub",
    "Dim http, reqBody",
    "reqBody = \"\"",
    "If " .. vbs_quote(body_path) .. " <> \"\" Then reqBody = ReadUtf8(" .. vbs_quote(body_path) .. ")",
    "Set http = CreateObject(\"MSXML2.ServerXMLHTTP.6.0\")",
    "http.setTimeouts 15000, 15000, 30000, 30000",
    "http.open " .. vbs_quote(method) .. ", " .. vbs_quote(url) .. ", False",
    "If " .. vbs_quote(content_type or "") .. " <> \"\" Then http.setRequestHeader \"Content-Type\", " .. vbs_quote(content_type or ""),
    "http.setRequestHeader \"User-Agent\", \"dtrmflickr-darktable-lua\"",
    "http.send reqBody",
    "If Err.Number <> 0 Then",
    "  WriteUtf8 " .. vbs_quote(err_path) .. ", \"MSXML HTTP failed (\" & CStr(Err.Number) & \"): \" & Err.Description",
    "  WScript.Quit 1",
    "End If",
    "WriteUtf8 " .. vbs_quote(out_path) .. ", http.responseText",
    "WScript.Quit 0",
  }, "\r\n")

  if not write_file(vbs_path, script) then return nil, "could not write temporary HTTP script" end
  local ok, why, code = launch_windows("wscript.exe //B //Nologo " .. shq(vbs_path))

  local out = read_file(out_path) or ""
  local err = read_file(err_path) or ""
  os.remove(vbs_path)
  if body_path ~= "" then os.remove(body_path) end
  os.remove(out_path)
  os.remove(err_path)
  if not command_succeeded(ok, why, code) then
    local detail = err ~= "" and err or out
    return nil, detail ~= "" and detail or ("HTTP helper failed: " .. tostring(why or code or ok))
  end
  return out ~= "" and out or err
end

function run(cmd)
  if is_windows() then return run_windows_hidden(cmd) end
  local p = io.popen(cmd .. " 2>&1")
  if not p then return nil, "io.popen failed" end
  local out = p:read("*a")
  local ok, why, code = p:close()
  if not command_succeeded(ok, why, code) then
    return nil, out ~= "" and out or ("command failed: " .. tostring(why or code or ok))
  end
  return out
end
M.run = run

function M.quiet_rest_available()
  return not is_windows() or (native_http_ok and native_http and native_http.request ~= nil)
end

function M.native_status()
  if native_http_ok then return true, native_http_error or "native HTTP loaded" end
  return false, native_http_error or "native HTTP unavailable"
end

-- GET url -> body (string). curl flags: -s silent, -S show errors, -L follow.
function M.get(url)
  if is_windows() and native_http_ok and native_http and native_http.request then
    return native_http.request("GET", url)
  end
  if is_windows() then return windows_http("GET", url) end
  return run_curl_config({
    "silent",
    "show-error",
    "location",
    "url = " .. curl_config_quote(url),
  })
end

-- POST application/x-www-form-urlencoded.
--   body: an already-encoded "a=b&c=d" string.
function M.post(url, body)
  if is_windows() and native_http_ok and native_http and native_http.request then
    return native_http.request("POST", url, body or "", "application/x-www-form-urlencoded")
  end
  if is_windows() then return windows_http("POST", url, body or "", "application/x-www-form-urlencoded") end
  return run_curl_config({
    "silent",
    "show-error",
    "location",
    "data = " .. curl_config_quote(body),
    "url = " .. curl_config_quote(url),
  })
end

-- POST multipart/form-data.
--   fields: table of string form fields.
--   file_field/file_path: uploaded file field, e.g. photo=@C:\path\out.jpg.
function M.post_multipart(url, fields, file_field, file_path)
  local keys = {}
  for k in pairs(fields or {}) do keys[#keys + 1] = k end
  table.sort(keys)

  local lines = {
    "silent",
    "show-error",
    "location",
  }
  for _, k in ipairs(keys) do
    -- --form-string prevents values starting with @ or containing ;type= from
    -- being interpreted as curl file/content-type syntax.
    lines[#lines + 1] = "form-string = " .. curl_config_quote(tostring(k) .. "=" .. tostring(fields[k]))
  end
  lines[#lines + 1] = "form = " .. curl_config_quote(tostring(file_field) .. "=@" .. tostring(file_path))
  lines[#lines + 1] = "url = " .. curl_config_quote(url)
  return run_curl_config(lines)
end

return M
end

package.preload["dtrmflickr.flickr_auth"] = function(...)
-- flickr_auth.lua — Flickr OAuth 1.0a three-legged handshake (oob flow).
--
-- Pure logic: depends only on the signer (oauth.lua) and an HTTP module. The
-- HTTP module is injectable (M.http) so the flow can be unit-tested offline
-- with a fake transport. Token *persistence* lives in the main plugin (it needs
-- darktable.password); this module only performs the handshake.
--
-- Endpoints (dedicated OAuth endpoints, NOT the REST method of the same name):
--   request_token -> authorize (browser) -> access_token
-- All return application/x-www-form-urlencoded bodies.

local oauth = require "dtrmflickr.oauth"

local M = { http = require "dtrmflickr.http" }

M.REQUEST_TOKEN_URL = "https://www.flickr.com/services/oauth/request_token"
M.AUTHORIZE_URL     = "https://www.flickr.com/services/oauth/authorize"
M.ACCESS_TOKEN_URL  = "https://www.flickr.com/services/oauth/access_token"

----------------------------------------------------------------------
-- helpers
----------------------------------------------------------------------
local function urldecode(s)
  s = tostring(s or "")
  s = s:gsub("+", " "):gsub("%%(%x%x)", function(h) return string.char(tonumber(h, 16)) end)
  return s
end

-- parse "a=b&c=d" -> { a = "b", c = "d" }
local function parse_form(body)
  local t = {}
  for k, v in tostring(body):gmatch("([^&=]+)=([^&]*)") do
    t[urldecode(k)] = urldecode(v)
  end
  return t
end
M.parse_form = parse_form

local seq = 0
local function nonce()
  seq = seq + 1
  return string.format("%d%06d%d", os.time(), math.floor((os.clock() % 1) * 1e6), seq)
end

-- Sign `params` and return a full URL with the signed query string appended.
-- `params` must NOT contain oauth_signature (added here after signing).
local function signed_url(method, base_url, params, consumer_secret, token_secret)
  local sig = oauth.signature(method, base_url, params, consumer_secret, token_secret)
  params.oauth_signature = sig
  local keys = {}
  for k in pairs(params) do keys[#keys + 1] = k end
  table.sort(keys)
  local parts = {}
  for _, k in ipairs(keys) do
    parts[#parts + 1] = oauth.encode(k) .. "=" .. oauth.encode(params[k])
  end
  return base_url .. "?" .. table.concat(parts, "&")
end
M.signed_url = signed_url

local function base_params(api_key)
  return {
    oauth_consumer_key     = api_key,
    oauth_nonce            = nonce(),
    oauth_signature_method = "HMAC-SHA1",
    oauth_timestamp        = tostring(os.time()),
    oauth_version          = "1.0",
  }
end

----------------------------------------------------------------------
-- step 1: request token (oauth_callback = oob)
--   -> token, token_secret   |   nil, error_body
----------------------------------------------------------------------
function M.get_request_token(api_key, api_secret)
  local params = base_params(api_key)
  params.oauth_callback = "oob"
  local url = signed_url("GET", M.REQUEST_TOKEN_URL, params, api_secret, "")
  local body, err = M.http.get(url)
  if not body then return nil, err end
  local r = parse_form(body)
  if r.oauth_token and r.oauth_token_secret then
    return r.oauth_token, r.oauth_token_secret
  end
  return nil, body
end

----------------------------------------------------------------------
-- step 2: the URL the user visits to authorize (then Flickr shows a verifier)
----------------------------------------------------------------------
function M.authorize_url(request_token, perms)
  return M.AUTHORIZE_URL
    .. "?oauth_token=" .. oauth.encode(request_token)
    .. "&perms=" .. oauth.encode(perms or "write")
end

----------------------------------------------------------------------
-- step 3: exchange the verifier for a permanent access token
--   -> { token, secret, nsid, username, fullname }   |   nil, error_body
----------------------------------------------------------------------
function M.get_access_token(api_key, api_secret, req_token, req_secret, verifier)
  local params = base_params(api_key)
  params.oauth_token    = req_token
  params.oauth_verifier = verifier
  local url = signed_url("GET", M.ACCESS_TOKEN_URL, params, api_secret, req_secret)
  local body, err = M.http.get(url)
  if not body then return nil, err end
  local r = parse_form(body)
  if r.oauth_token and r.oauth_token_secret then
    return {
      token    = r.oauth_token,
      secret   = r.oauth_token_secret,
      nsid     = r.user_nsid,
      username = r.username,
      fullname = r.fullname,
    }
  end
  return nil, body
end

return M
end

package.preload["dtrmflickr.flickr_upload"] = function(...)
-- flickr_upload.lua — signed Flickr multipart upload.
--
-- Flickr upload is not a normal REST method. It POSTs multipart/form-data to
-- up.flickr.com, and the binary "photo" part is excluded from the OAuth
-- signature. All text form fields, including upload options, are signed.

local oauth = require "dtrmflickr.oauth"

local M = { http = require "dtrmflickr.http" }

M.UPLOAD_URL = "https://up.flickr.com/services/upload/"

local seq = 0
local function nonce()
  seq = seq + 1
  return string.format("%d%06d%d", os.time(), math.floor((os.clock() % 1) * 1e6), seq)
end

local function base_params(api_key, access_token)
  return {
    oauth_consumer_key     = api_key,
    oauth_nonce            = nonce(),
    oauth_signature_method = "HMAC-SHA1",
    oauth_timestamp        = tostring(os.time()),
    oauth_token            = access_token,
    oauth_version          = "1.0",
  }
end

local function add_if_present(params, name, value)
  if value ~= nil and value ~= "" then params[name] = tostring(value) end
end

local function xml_unescape(s)
  return tostring(s or "")
    :gsub("&#x(%x+);", function(h)
      local n = tonumber(h, 16)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&#(%d+);", function(d)
      local n = tonumber(d, 10)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&quot;", '"')
    :gsub("&apos;", "'")
    :gsub("&lt;", "<")
    :gsub("&gt;", ">")
    :gsub("&amp;", "&")
end

local function parse_upload_response(body)
  body = tostring(body or "")
  if body:find('stat%s*=%s*"ok"') or body:find("stat%s*=%s*'ok'") then
    local photo_id = body:match("<photoid>(.-)</photoid>")
    if photo_id and photo_id ~= "" then return xml_unescape(photo_id) end
    local ticket_id = body:match("<ticketid>(.-)</ticketid>")
    if ticket_id and ticket_id ~= "" then return nil, "async upload returned ticket " .. xml_unescape(ticket_id) end
    return nil, "Flickr upload succeeded but returned no photoid"
  end

  local msg = body:match('<err[^>]-msg="(.-)"') or body:match("<err[^>]-msg='(.-)'")
  local code = body:match('<err[^>]-code="(.-)"') or body:match("<err[^>]-code='(.-)'")
  if msg then
    return nil, code and ("Flickr upload failed (" .. code .. "): " .. xml_unescape(msg))
      or ("Flickr upload failed: " .. xml_unescape(msg))
  end
  return nil, body ~= "" and body or "empty Flickr upload response"
end
M.parse_upload_response = parse_upload_response

-- upload_photo(...) -> photo_id | nil, err
--
-- account: { token = "...", secret = "..." }
-- opts: title, description, tags, is_public, is_friend, is_family,
--       safety_level, content_type, hidden, perm_comment, perm_addmeta
function M.upload_photo(api_key, api_secret, account, filename, opts)
  if not account or not account.token or not account.secret then
    return nil, "not logged in to Flickr"
  end
  if not filename or filename == "" then
    return nil, "missing upload filename"
  end

  local params = base_params(api_key, account.token)
  opts = opts or {}
  add_if_present(params, "title", opts.title)
  add_if_present(params, "description", opts.description)
  add_if_present(params, "tags", opts.tags)
  add_if_present(params, "is_public", opts.is_public)
  add_if_present(params, "is_friend", opts.is_friend)
  add_if_present(params, "is_family", opts.is_family)
  add_if_present(params, "safety_level", opts.safety_level)
  add_if_present(params, "content_type", opts.content_type)
  add_if_present(params, "hidden", opts.hidden)
  add_if_present(params, "perm_comment", opts.perm_comment)
  add_if_present(params, "perm_addmeta", opts.perm_addmeta)

  params.oauth_signature = oauth.signature("POST", M.UPLOAD_URL, params, api_secret, account.secret)
  local body, transport_err = M.http.post_multipart(M.UPLOAD_URL, params, "photo", filename)
  if not body then return nil, transport_err end
  return parse_upload_response(body)
end

return M
end

package.preload["dtrmflickr.flickr_rest"] = function(...)
-- flickr_rest.lua — signed Flickr REST API calls used after upload.
--
-- Uploads go through up.flickr.com (see flickr_upload.lua). Album/photoset
-- operations are normal REST methods posted to flickr.com/services/rest/.

local oauth = require "dtrmflickr.oauth"

local M = { http = require "dtrmflickr.http" }

M.REST_URL = "https://www.flickr.com/services/rest/"

local seq = 0
local function nonce()
  seq = seq + 1
  return string.format("%d%06d%d", os.time(), math.floor((os.clock() % 1) * 1e6), seq)
end

local function base_params(api_key, access_token)
  return {
    api_key                = api_key,
    oauth_consumer_key     = api_key,
    oauth_nonce            = nonce(),
    oauth_signature_method = "HMAC-SHA1",
    oauth_timestamp        = tostring(os.time()),
    oauth_token            = access_token,
    oauth_version          = "1.0",
  }
end

local function form_encode(params)
  local keys = {}
  for k in pairs(params or {}) do keys[#keys + 1] = k end
  table.sort(keys)

  local parts = {}
  for _, k in ipairs(keys) do
    parts[#parts + 1] = oauth.encode(k) .. "=" .. oauth.encode(params[k])
  end
  return table.concat(parts, "&")
end
M.form_encode = form_encode

local function xml_unescape(s)
  return tostring(s or "")
    :gsub("&#x(%x+);", function(h)
      local n = tonumber(h, 16)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&#(%d+);", function(d)
      local n = tonumber(d, 10)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&quot;", '"')
    :gsub("&apos;", "'")
    :gsub("&lt;", "<")
    :gsub("&gt;", ">")
    :gsub("&amp;", "&")
end

local function parse_error(body)
  body = tostring(body or "")
  local msg = body:match('<err[^>]-msg="(.-)"') or body:match("<err[^>]-msg='(.-)'")
  local code = body:match('<err[^>]-code="(.-)"') or body:match("<err[^>]-code='(.-)'")
  if msg then
    return code and ("Flickr REST failed (" .. code .. "): " .. xml_unescape(msg))
      or ("Flickr REST failed: " .. xml_unescape(msg))
  end
  return body ~= "" and body or "empty Flickr REST response"
end
M.parse_error = parse_error

local function ok(body)
  body = tostring(body or "")
  return body:find('stat%s*=%s*"ok"') or body:find("stat%s*=%s*'ok'")
end

function M.call(api_key, api_secret, account, method, args)
  if not account or not account.token or not account.secret then
    return nil, "not logged in to Flickr"
  end
  if not method or method == "" then return nil, "missing Flickr REST method" end

  local params = base_params(api_key, account.token)
  params.method = method
  for k, v in pairs(args or {}) do
    if k ~= "_allow_empty" and v ~= nil and (v ~= "" or (args._allow_empty and args._allow_empty[k])) then
      params[k] = tostring(v)
    end
  end

  params.oauth_signature = oauth.signature("POST", M.REST_URL, params, api_secret, account.secret)
  local body, transport_err = M.http.post(M.REST_URL, form_encode(params))
  if not body then return nil, transport_err end
  if ok(body) then return body end
  return nil, parse_error(body)
end

function M.public_call(api_key, method, args)
  if not api_key or api_key == "" then return nil, "missing Flickr API key" end
  if not method or method == "" then return nil, "missing Flickr REST method" end

  local params = {
    api_key = api_key,
    method = method,
  }
  for k, v in pairs(args or {}) do
    if k ~= "_allow_empty" and v ~= nil and (v ~= "" or (args._allow_empty and args._allow_empty[k])) then
      params[k] = tostring(v)
    end
  end

  local body, transport_err = M.http.post(M.REST_URL, form_encode(params))
  if not body then return nil, transport_err end
  if ok(body) then return body end
  return nil, parse_error(body)
end

function M.photosets_create(api_key, api_secret, account, title, primary_photo_id, description)
  if not title or title == "" then return nil, "missing album title" end
  if not primary_photo_id or primary_photo_id == "" then return nil, "missing primary photo id" end

  local body, err = M.call(api_key, api_secret, account, "flickr.photosets.create", {
    title = title,
    description = description,
    primary_photo_id = primary_photo_id,
  })
  if not body then return nil, err end

  local photoset_id = body:match('<photoset[^>]-id="(.-)"') or body:match("<photoset[^>]-id='(.-)'")
  if photoset_id and photoset_id ~= "" then return xml_unescape(photoset_id), body end
  return nil, "Flickr created the album but returned no photoset id"
end

function M.photosets_add_photo(api_key, api_secret, account, photoset_id, photo_id)
  if not photoset_id or photoset_id == "" then return nil, "missing photoset id" end
  if not photo_id or photo_id == "" then return nil, "missing photo id" end

  local body, err = M.call(api_key, api_secret, account, "flickr.photosets.addPhoto", {
