package.preload["dtrmflickr.state"] = function(...)
-- state.lua — per-image Flickr publish state.
--
-- This is the only module that knows how state is persisted. The current
-- backend is image tags because they are Lua-writable, per-image, multi-valued,
-- and survive through XMP sidecars when sidecars are enabled.

local dt = require "darktable"

local M = {}

local PREFIX <const> = "dtrmflickr"

local function tag_name(tag)
  return tag and tag.name or nil
end

local function photo_tag(account_nsid, photo_id)
  return table.concat({ PREFIX, tostring(account_nsid), tostring(photo_id) }, "|")
end

local function set_tag(account_nsid, set_id)
  return table.concat({ PREFIX, tostring(account_nsid), "set", tostring(set_id) }, "|")
end

local function valid_component(value)
  value = tostring(value or "")
  return value ~= "" and value:find("|", 1, true) == nil
end

local function assert_component(kind, value)
  assert(valid_component(value), "invalid Flickr " .. kind)
end

local function ensure_tag(name)
  return dt.tags.find(name) or dt.tags.create(name)
end

local function image_tags(image)
  if image and image.get_tags then return image:get_tags() end
  return dt.tags.get_tags(image)
end

local function attach(image, tag)
  if image and image.attach_tag then return image:attach_tag(tag) end
  return dt.tags.attach(tag, image)
end

local function detach(image, tag)
  if image and image.detach_tag then return image:detach_tag(tag) end
  return dt.tags.detach(tag, image)
end

function M.is_plugin_tag(name)
  return type(name) == "string" and (name == PREFIX or name:sub(1, #PREFIX + 1) == PREFIX .. "|")
end

function M.get_photo_id(image, account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local id = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if id and id ~= "" and not id:find("|", 1, true) then return id end
  end
  return nil
end

function M.get_any_photo_id(image)
  local prefix = PREFIX .. "|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #prefix) == prefix then
      local rest = name:sub(#prefix + 1)
      local account_nsid, photo_id = rest:match("^([^|]+)|([^|]+)$")
      if account_nsid and photo_id then return account_nsid, photo_id end
    end
  end
  return nil, nil
end

function M.set_photo_id(image, account_nsid, photo_id)
  assert_component("account id", account_nsid)
  assert_component("photo id", photo_id)
  local old_id = M.get_photo_id(image, account_nsid)
  if old_id and old_id ~= tostring(photo_id) then
    local old_tag = dt.tags.find(photo_tag(account_nsid, old_id))
    if old_tag then detach(image, old_tag) end
  end
  attach(image, ensure_tag(photo_tag(account_nsid, photo_id)))
end

function M.clear_photo_id(image, account_nsid)
  assert_component("account id", account_nsid)
  local old_id = M.get_photo_id(image, account_nsid)
  if not old_id then return false end
  local old_tag = dt.tags.find(photo_tag(account_nsid, old_id))
  if old_tag then detach(image, old_tag) end
  return true
end

function M.get_sets(image, account_nsid)
  assert_component("account id", account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|set|"
  local sets = {}
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local id = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if valid_component(id) then sets[#sets + 1] = id end
  end
  table.sort(sets)
  return sets
end

function M.add_set(image, account_nsid, set_id)
  assert_component("account id", account_nsid)
  assert_component("set id", set_id)
  attach(image, ensure_tag(set_tag(account_nsid, set_id)))
end

function M.remove_set(image, account_nsid, set_id)
  assert_component("account id", account_nsid)
  assert_component("set id", set_id)
  local tag = dt.tags.find(set_tag(account_nsid, set_id))
  if tag then detach(image, tag) end
end

function M.clear_sets(image, account_nsid)
  local removed = 0
  for _, set_id in ipairs(M.get_sets(image, account_nsid)) do
    M.remove_set(image, account_nsid, set_id)
    removed = removed + 1
  end
  return removed
end

function M.clear_account(image, account_nsid)
  local removed = M.clear_sets(image, account_nsid)
  if M.clear_photo_id(image, account_nsid) then removed = removed + 1 end
  return removed
end

function M.clear_other_accounts(image, keep_account_nsid)
  local keep = tostring(keep_account_nsid)
  local accounts = {}
  local prefix = PREFIX .. "|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #prefix) == prefix then
      local account_nsid = name:sub(#prefix + 1):match("^([^|]+)|")
      if account_nsid and account_nsid ~= keep then accounts[account_nsid] = true end
    end
  end
  local removed = 0
  for account_nsid in pairs(accounts) do
    removed = removed + M.clear_account(image, account_nsid)
  end
  return removed
end

return M
end

package.preload["dtrmflickr.metadata"] = function(...)
local dt = require "darktable"
local state = require "dtrmflickr.state"

local M = {}

local TAG_FLAG_CATEGORY <const> = 1
local TAG_FLAG_PRIVATE <const> = 2

function M.image_title(image, filename)
  if image and image.title and image.title ~= "" then return image.title end
  if image and image.filename and image.filename ~= "" then return image.filename end
  return tostring(filename or ""):match("[^/\\]+$") or tostring(filename or "")
end

function M.image_date_taken(image)
  local value = image and image.exif_datetime_taken or nil
  value = value and tostring(value):match("^%s*(.-)%s*$") or nil
  if not value or value == "" then return nil end
  local y, mo, d, h, mi, s = value:match("^(%d%d%d%d)[:%-](%d%d)[:%-](%d%d)%s+(%d%d):(%d%d):(%d%d)")
  if not y then return nil end
  -- Flickr date_taken is a timezone-less taken-local-time field. Do not convert
  -- from darktable's EXIF taken time; just normalize to MySQL datetime syntax.
  return string.format("%s-%s-%s %s:%s:%s", y, mo, d, h, mi, s)
end

local function flickr_coordinate(value, min_value, max_value)
  local n = tonumber(value)
  if not n or n ~= n or n < min_value or n > max_value then return nil end
  return string.format("%.6f", n)
end

function M.image_location(image)
  local lat = flickr_coordinate(image and image.latitude or nil, -90, 90)
  local lon = flickr_coordinate(image and image.longitude or nil, -180, 180)
  if lat == nil or lon == nil then return nil, nil end
  return lat, lon
end

local function image_tags(image)
  local tags = {}
  if image and image.get_tags then
    tags = image:get_tags() or {}
  else
    tags = dt.tags.get_tags(image) or {}
  end
  table.sort(tags, function(a, b) return tostring(a and a.name or "") < tostring(b and b.name or "") end)
  return tags
end

function M.image_tag_names(image)
  local names = {}
  for _, tag in ipairs(image_tags(image)) do
    local name = tag and tag.name or nil
    if name and name ~= "" then names[#names + 1] = name end
  end
  return names
end

function M.tag_matches_filter(tag_name, filter)
  filter = tostring(filter or ""):match("^%s*(.-)%s*$"):lower()
  if filter == "" then return false end
  return tostring(tag_name or ""):lower():find(filter, 1, true) ~= nil
end

local function flickr_quote_tag(tag)
  tag = tostring(tag or "")
  if tag:find("%s") then return '"' .. tag .. '"' end
  return tag
end

local function publish_tag_name(name)
  name = tostring(name or ""):match("^%s*(.-)%s*$")
  local leaf = name:match("([^|]+)$")
  leaf = leaf and leaf:match("^%s*(.-)%s*$") or name
  leaf = leaf:gsub('"', ""):match("^%s*(.-)%s*$")
  return leaf ~= "" and leaf or nil
end

local function tag_flags(tag)
  return tonumber(tag and tag.flags or 0) or 0
end

local function tag_is_private_or_category(tag)
  local flags = tag_flags(tag)
  return (flags & (TAG_FLAG_PRIVATE | TAG_FLAG_CATEGORY)) ~= 0
end

local function has_private_category_parent(name)
  name = tostring(name or "")
  local parent = name:match("^(.*)|[^|]+$")
  while parent and parent ~= "" do
    local parent_tag = dt.tags and dt.tags.find and dt.tags.find(parent) or nil
    local flags = tag_flags(parent_tag)
    if (flags & (TAG_FLAG_PRIVATE | TAG_FLAG_CATEGORY)) == (TAG_FLAG_PRIVATE | TAG_FLAG_CATEGORY) then
      return true
    end
    parent = parent:match("^(.*)|[^|]+$")
  end
  return false
end

local function tag_is_publishable_keyword(tag)
  local name = tag and tag.name or nil
  if not name or name == "" then return false end
  if state.is_plugin_tag(name) or name:match("^darktable|") ~= nil then return false end
  if tag_is_private_or_category(tag) then return false end
  if has_private_category_parent(name) then return false end
  return true
end

function M.image_keyword_tags(image, excluded_filters, tag_names, opts)
  opts = opts or {}
  local tags = {}
  local seen = {}
  local source_tags = {}
  if tag_names then
    for _, name in ipairs(tag_names) do source_tags[#source_tags + 1] = { name = name } end
  else
    source_tags = image_tags(image)
  end
  table.sort(source_tags, function(a, b) return tostring(a and a.name or "") < tostring(b and b.name or "") end)

  for _, tag in ipairs(source_tags) do
    local name = tag and tag.name or nil
    if name and name ~= "" then
      local excluded = not tag_is_publishable_keyword(tag)
      for _, filter in ipairs(excluded_filters or {}) do
        if M.tag_matches_filter(name, filter) then excluded = true; break end
      end
      if not excluded then
        local publish_name = publish_tag_name(name)
        local key = publish_name and publish_name:lower() or nil
        if publish_name and not seen[key] then
          seen[key] = true
          tags[#tags + 1] = publish_name
        end
      end
    end
  end

  table.sort(tags, function(a, b) return tostring(a):lower() < tostring(b):lower() end)
  local original_count = #tags
  if opts.max_tags and #tags > opts.max_tags then
    local limited = {}
    for i = 1, opts.max_tags do limited[i] = tags[i] end
    tags = limited
  end

  local encoded = {}
  for _, tag in ipairs(tags) do encoded[#encoded + 1] = flickr_quote_tag(tag) end
  return #encoded > 0 and table.concat(encoded, " ") or nil, math.max(0, original_count - #tags)
end

return M
end

package.preload["dtrmflickr.claim"] = function(...)
local dt = require "darktable"
local rest = require "dtrmflickr.flickr_rest"
local state = require "dtrmflickr.state"
local metadata = require "dtrmflickr.metadata"

local M = {}

local function remote_attr(body, name)
  return body and (body:match(name .. '="(.-)"') or body:match(name .. "='(.-)'")) or nil
end

local function xml_unescape(s)
  return tostring(s or "")
    :gsub("&#x(%x+);", function(h)
      local n = tonumber(h, 16)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&#(%d+);", function(d)
      local n = tonumber(d, 10)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&quot;", '"')
    :gsub("&apos;", "'")
    :gsub("&lt;", "<")
    :gsub("&gt;", ">")
    :gsub("&amp;", "&")
end

local function filename_part(value)
  return tostring(value or ""):match("[^/\\]+$") or tostring(value or "")
end

local function basename_part(value)
  local file = filename_part(value)
  return file:match("^(.*)%.[^%.]+$") or file
end

local function normalize_match_text(value)
  value = xml_unescape(value or ""):lower()
  value = value:gsub("^%s+", ""):gsub("%s+$", "")
  return value
end

function M.claim_match_terms(image)
  local terms, seen = {}, {}
  local function add(value)
    value = normalize_match_text(value)
    if value ~= "" and not seen[value] then
      seen[value] = true
      terms[#terms + 1] = value
    end
  end
  add(image and image.filename)
  add(basename_part(image and image.filename))
  add(image and image.title)
  add(basename_part(image and image.title))
  if image and dt.metadata and type(dt.metadata.exists) == "function" then
    local ok_exists, exists = pcall(dt.metadata.exists, "Xmp.xmpMM.PreservedFileName")
    if ok_exists and exists then
      local ok_value, preserved = pcall(function() return image["preserved filename"] end)
      if ok_value and type(preserved) == "string" then
        preserved = preserved:match("^%s*(.-)%s*$")
        add(preserved)
        add(basename_part(preserved))
      end
    end
  end
  return terms
end

function M.parse_search_photos(body)
  local photos = {}
  for attrs in tostring(body or ""):gmatch("<photo%s+([^>]-)/>") do
    photos[#photos + 1] = {
      id = remote_attr(attrs, "id"),
      title = xml_unescape(remote_attr(attrs, "title") or ""),
      datetaken = remote_attr(attrs, "datetaken"),
      dateupload = remote_attr(attrs, "dateupload"),
    }
  end
  for attrs in tostring(body or ""):gmatch("<photo%s+([^>]-)>") do
    if not attrs:match("/%s*$") then
      photos[#photos + 1] = {
        id = remote_attr(attrs, "id"),
        title = xml_unescape(remote_attr(attrs, "title") or ""),
        datetaken = remote_attr(attrs, "datetaken"),
        dateupload = remote_attr(attrs, "dateupload"),
      }
    end
  end
  return photos
end

local function add_candidate(candidates, photo, reason)
  if not photo or not photo.id or photo.id == "" then return end
  local current = candidates[photo.id]
  if not current then
    candidates[photo.id] = {
      id = photo.id,
      title = photo.title,
      datetaken = photo.datetaken,
      dateupload = photo.dateupload,
      reasons = {},
    }
    current = candidates[photo.id]
  end
  current.reasons[reason] = true
end

local function candidate_list(candidates)
  local list = {}
  for _, item in pairs(candidates or {}) do list[#list + 1] = item end
  table.sort(list, function(a, b) return tostring(a.id) < tostring(b.id) end)
  return list
end

local function candidate_title_matches(candidate, terms)
  local title = normalize_match_text(candidate and candidate.title)
  if title == "" then return false end
  local title_base = normalize_match_text(basename_part(title))
  for _, term in ipairs(terms or {}) do
    if title == term or title_base == term then return true end
  end
  return false
end

local function search_existing_candidates(api_key, api_secret, acc, image)
  local candidates, errors = {}, {}
  local terms = M.claim_match_terms(image)
  local taken = metadata.image_date_taken(image)

  local function run_search(args, reason)
    args = args or {}
    args.user_id = acc.nsid
    args.media = "photos"
    args.extras = "date_taken,date_upload,original_format"
    args.per_page = 50
    args.page = 1
    local body, err = rest.photos_search(api_key, api_secret, acc, args)
    if not body then
      errors[#errors + 1] = tostring(err)
      return
    end
    for _, photo in ipairs(M.parse_search_photos(body)) do
      add_candidate(candidates, photo, reason)
    end
  end

  if taken then
    run_search({ min_taken_date = taken, max_taken_date = taken, sort = "date-taken-desc" }, "taken")
  end
  for _, term in ipairs(terms) do
    run_search({ text = term, sort = "relevance" }, "text")
  end

  return candidate_list(candidates), terms, taken, errors
end

function M.choose_existing_match(candidates, terms, taken)
  local exact_date = {}
  if taken then
    for _, candidate in ipairs(candidates or {}) do
      if candidate.datetaken == taken or candidate.reasons.taken then exact_date[#exact_date + 1] = candidate end
    end
    if #exact_date == 1 then return exact_date[1], "exact date/time" end
  end

  local title_matches = {}
  for _, candidate in ipairs(candidates or {}) do
    if candidate_title_matches(candidate, terms) and (not taken or candidate.datetaken == taken or candidate.reasons.taken) then
      title_matches[#title_matches + 1] = candidate
    end
  end
  if #title_matches == 1 then
    return title_matches[1], taken and "title/filename + date/time" or "title/filename"
  end

  if #exact_date > 1 then return nil, "ambiguous exact date/time" end
  if #title_matches > 1 then return nil, "ambiguous title/filename" end
  return nil, #candidates > 0 and "no strong unique match" or "no match"
end

function M.claim_existing_for_image(api_key, api_secret, acc, image)
  if state.get_photo_id(image, acc.nsid) then return "skipped", "already linked" end
  local candidates, terms, taken, errors = search_existing_candidates(api_key, api_secret, acc, image)
  local match, reason = M.choose_existing_match(candidates, terms, taken)
  if match then
    state.set_photo_id(image, acc.nsid, match.id)
    return "claimed", string.format("%s (%s)", tostring(match.id), reason)
  end
  if #errors > 0 and #candidates == 0 then return "error", table.concat(errors, "; ") end
  return "skipped", reason
end

return M
end

