local TRANSPORT, TRANSPORT_MSG = detect_transport()

----------------------------------------------------------------------
-- Preferences / token persistence.
--   consumer key+secret -> registered prefs (app identity, edited in Lua Options)
--   access token+secret -> darktable.password keyed (PLUGIN, nsid)  [secret]
--   active account nsid + display name -> unregistered prefs        [internal]
