local function json_escape(s)
  return tostring(s or ""):gsub('[%z\1-\31\\"]', function(c)
    if c == "\\" then return "\\\\" end
    if c == '"' then return '\\"' end
    return string.format("\\u%04x", c:byte())
  end)
end

local function json_object(fields)
  return string.format('{"server":"%s","username":"%s","password":"%s"}',
    json_escape(fields.server), json_escape(fields.username), json_escape(fields.password))
end

local function json_unescape(s)
  s = tostring(s or ""):gsub("\\u(%x%x%x%x)", function(h)
    local n = tonumber(h, 16)
    if n and n < 128 then return string.char(n) end
    return ""
  end)
  return s
    :gsub("\\t", "\t")
    :gsub("\\r", "\r")
    :gsub("\\n", "\n")
