end

local function permission_index_from_pref(value)
  for i, v in ipairs(permission_values) do
    if v.pref == value then return i end
  end
  return 4
end

local DEFAULT_SETTING_PREF_TYPE <const> = "string"

local function read_stored_default_pref(name, default_value)
  local value = dt.preferences.read(PLUGIN, name, DEFAULT_SETTING_PREF_TYPE)
    or dt.preferences.read(PLUGIN, name, "enum")
    or dt.preferences.read(PLUGIN, name, "lua")
  if value == nil or value == "" then
    dt.preferences.write(PLUGIN, name, DEFAULT_SETTING_PREF_TYPE, default_value)
    return default_value
  end
  dt.preferences.write(PLUGIN, name, DEFAULT_SETTING_PREF_TYPE, value)
  return value
end

local default_setting_specs = {
  { name = "default_privacy", label = _("privacy"), values = privacy_values, default = "private" },
  { name = "default_safety", label = _("safety"), values = safety_values, default = "safe" },
  { name = "default_content_type", label = _("content type"), values = content_type_values, default = "photo" },
  { name = "default_license", label = _("license"), values = license_values, default = "CC BY-NC-SA 4.0" },
  { name = "default_comment_perm", label = _("allow commenting"), values = permission_values, default = "any Flickr member" },
  { name = "default_addmeta_perm", label = _("allow tags, notes, people"), values = permission_values, default = "any Flickr member" },
}

local default_setting_specs_by_name = {}
for _, spec in ipairs(default_setting_specs) do
  default_setting_specs_by_name[spec.name] = spec
end

local function default_index_from_pref(spec, value)
  for i, item in ipairs(spec.values) do
    if item.pref == value then
      return i
    end
  end
  return 1
end

local function read_default_pref(name, default_value)
  local spec = default_setting_specs_by_name[name]
  if not spec then return read_stored_default_pref(name, default_value) end

  local index = default_index_from_pref(spec, read_stored_default_pref(name, default_value))
  local selected = spec.values[index]
  dt.preferences.write(PLUGIN, name, DEFAULT_SETTING_PREF_TYPE, selected.pref)
  return selected.pref
end

local sync_field_defaults = {
  title = true,
  description = true,
  tags = true,
  date_taken = true,
  gps = false,
  privacy = true,
  safety = true,
  content_type = true,
  license = true,
  permissions = true,
}
local sync_widgets = {}

local function read_sync_pref(name)
  local value = dt.preferences.read(PLUGIN, "sync_" .. name, "bool")
  if value == nil then return sync_field_defaults[name] == true end
  return value == true
end

local function write_sync_pref(name, value)
  dt.preferences.write(PLUGIN, "sync_" .. name, "bool", value == true)
end

local function current_sync_fields()
  local fields = {}
  for name in pairs(sync_field_defaults) do
    local widget = sync_widgets[name]
    fields[name] = widget and widget.value == true or read_sync_pref(name)
    write_sync_pref(name, fields[name])
  end
  return fields
end

local function master_sync_fields()
  local fields = {}
  for name in pairs(sync_field_defaults) do
    fields[name] = read_sync_pref(name)
  end
  return fields
end

local status_label = dt.new_widget("label") { label = "" }
local verifier_label = dt.new_widget("label") { label = _("verifier code") }

local verifier_entry = dt.new_widget("entry") {
  text = "",
  placeholder = _("9-digit code from Flickr"),
  tooltip = _("paste the code Flickr shows after you authorize"),
}

local pending = nil   -- { token, secret } held between 'log in' and 'complete login'
local last_error = nil
local complete_button
local login_button
local logout_button

local function short_error(err)
  local s = tostring(err or ""):gsub("%s+", " ")
  if #s > 160 then s = s:sub(1, 157) .. "..." end
  return s
end

local function refresh_status()
  local acc = load_token()
  local logged_in = acc ~= nil
  local waiting_for_verifier = pending ~= nil and not logged_in

  status_label.label = logged_in
    and (last_error
      and string.format(_("status: logged in as %s (not saved)"), acc.username or acc.nsid)
      or string.format(_("status: logged in as %s"), acc.username or acc.nsid))
    or last_error
      and string.format(_("status: login failed: %s"), last_error)
    or waiting_for_verifier
      and _("status: authorize in browser, paste the code, then 'complete login'")
      or  _("status: not logged in")

  verifier_label.visible = waiting_for_verifier
  verifier_entry.visible = waiting_for_verifier
  if complete_button then complete_button.visible = waiting_for_verifier end
  if login_button then login_button.visible = not logged_in end
  if logout_button then logout_button.visible = logged_in end
end

login_button = dt.new_widget("button") {
  label = _("log in to Flickr…"),
  clicked_callback = function()
    last_error = nil
    local key, secret = get_credentials()
    if not key then
      dt.print(_("Enter your Flickr API key and secret first."))
      return
    end
    dt.print(_("Requesting Flickr authorization…"))
    local tok, sec_or_err = auth.get_request_token(key, secret)
    if not tok then
      dt.print(_("Flickr request-token failed: ") .. tostring(sec_or_err))
      dt.print_log("[dtrmflickr] request_token error: " .. tostring(sec_or_err))
      return
    end
    pending = { token = tok, secret = sec_or_err }
    local url = auth.authorize_url(tok, "write")
    open_url(url)
    refresh_status()
    dt.print(_("Opened Flickr in your browser. Paste the verifier code and click 'complete login'."))
    dt.print_log("[dtrmflickr] authorize URL (open manually if browser didn't): " .. url)
  end,
}

complete_button = dt.new_widget("button") {
  label = _("complete login"),
  clicked_callback = function()
    if not pending then dt.print(_("Click 'log in to Flickr' first.")); return end
    last_error = nil
    local code = (verifier_entry.text or ""):gsub("%D", "")
    if code == "" then dt.print(_("Enter the verifier code from Flickr.")); return end
    local key, secret = get_credentials()
    if not key then dt.print(_("Enter your Flickr API key and secret first.")); return end
    local acc, err = auth.get_access_token(key, secret, pending.token, pending.secret, code)
    if not acc then
      last_error = short_error(err)
      refresh_status()
      dt.print(_("Flickr access-token failed: ") .. last_error)
      dt.print_log("[dtrmflickr] access_token error: " .. tostring(err))
      return
    end
    local saved, save_err = save_token(acc)
    if not saved then
      last_error = save_err
      pending = nil
      verifier_entry.text = ""
      refresh_status()
      dt.print(_("Flickr authorized for this session, but login was not saved: ") .. tostring(save_err))
      dt.print_log("[dtrmflickr] password_save error: " .. tostring(save_err))
      return
    end
    pending = nil
    last_error = nil
    verifier_entry.text = ""
    refresh_status()
    dt.print(string.format(_("Logged in to Flickr as %s"), acc.username or acc.nsid))
    dt.print_log("[dtrmflickr] logged in, nsid=" .. tostring(acc.nsid))
  end,
}

logout_button = dt.new_widget("button") {
  label = _("log out"),
  clicked_callback = function()
    clear_token()
    pending = nil
    last_error = nil
    refresh_status()
    dt.print(_("Logged out of Flickr."))
  end,
}

local account_widget = dt.new_widget("box") {
  orientation = "vertical",
  status_label,
  login_button,
  verifier_label,
  verifier_entry,
  complete_button,
  logout_button,
}

