local album_widget = dt.new_widget("combobox") {
  label = _("matching albums"),
  tooltip = _("matching fetched Flickr albums; select one or type an exact name/ID above"),
  selected = 0,
}
local album_status_label = dt.new_widget("label") { label = "" }
