----------------------------------------------------------------------
-- Storage callbacks.
----------------------------------------------------------------------
local supported_formats = { jpg = true, jpeg = true, tif = true, tiff = true, png = true, webp = true }

local function current_privacy()
  local index = privacy_widget.selected
  if not index or index == 0 then index = privacy_index_from_pref(privacy_widget.value) end
  local selected = privacy_values[index] or privacy_values[1]
  return {
    pref = selected.pref,
    is_public = selected.is_public,
    is_friend = selected.is_friend,
    is_family = selected.is_family,
  }
end

local function current_safety()
  local index = safety_widget.selected
  if not index or index == 0 then index = safety_index_from_pref(safety_widget.value) end
  local selected = safety_values[index] or safety_values[1]
  return {
    pref = selected.pref,
    flickr_value = selected.flickr_value,
  }
end

local function current_content_type()
  local index = content_type_widget.selected
  if not index or index == 0 then index = content_type_index_from_pref(content_type_widget.value) end
  local selected = content_type_values[index] or content_type_values[1]
  return {
    pref = selected.pref,
    flickr_value = selected.flickr_value,
  }
end

local function current_license()
  local index = license_widget.selected
  if not index or index == 0 then index = license_index_from_pref(license_widget.value) end
  local selected = license_values[index] or license_values[1]
  return {
    pref = selected.pref,
    flickr_value = selected.flickr_value,
  }
end

local function current_permissions()
  local comment_index = comment_perm_widget.selected
  if not comment_index or comment_index == 0 then comment_index = permission_index_from_pref(comment_perm_widget.value) end
  local addmeta_index = addmeta_perm_widget.selected
  if not addmeta_index or addmeta_index == 0 then addmeta_index = permission_index_from_pref(addmeta_perm_widget.value) end
  local comment = permission_values[comment_index] or permission_values[4]
  local addmeta = permission_values[addmeta_index] or permission_values[4]
  return {
    comment_pref = comment.pref,
    addmeta_pref = addmeta.pref,
    perm_comment = comment.flickr_value,
    perm_addmeta = addmeta.flickr_value,
  }
end

local function current_album()
  local mode = album_mode_widget.selected or 1
  local existing_value = album_input_value()
  local new_title = trim(album_new_entry.text or "")
  if mode == 2 and existing_value ~= "" then
    local match, match_kind = find_album_match(existing_value)
    if match then
      return {
        mode = "existing",
        photoset_id = match.id,
        title = match.title,
        match = match_kind,
      }
    end
    if existing_value:match("^%d+$") then return { mode = "existing", photoset_id = existing_value, match = "manual-id" } end
    return { mode = "none", error = "album not found or ambiguous", query = existing_value, match = match_kind }
  end
  if mode == 3 and new_title ~= "" then
    local match, match_kind = find_album_exact(new_title)
    if match then
      return {
        mode = "existing",
        photoset_id = match.id,
        title = match.title,
        duplicate_create = true,
        match = match_kind,
      }
    end
    return { mode = "create", title = new_title }
  end
  return { mode = "none" }
end

local function supported(storage, format)
  return supported_formats[format.extension] == true
end

local function initialize(storage, format, images, high_quality, extra_data)
  extra_data.uploaded = {}
  extra_data.failed   = {}
  extra_data.skipped  = {}
  extra_data.account  = load_token()
  extra_data.api_key, extra_data.api_secret = get_credentials()
  extra_data.privacy = current_privacy()
  extra_data.safety = current_safety()
  extra_data.content_type = current_content_type()
  extra_data.license = current_license()
  extra_data.permissions = current_permissions()
  extra_data.sync = current_sync_fields()
  extra_data.post_errors = {}
  extra_data.keyword_conflicts = {}
  extra_data.keyword_conflict_seen = {}
  local album_mode = album_mode_widget.selected or 1
  local wants_album = (album_mode == 2 and album_input_value() ~= "")
    or (album_mode == 3 and trim(album_new_entry.text or "") ~= "")
  if album_mode ~= 1 and wants_album and extra_data.account then
    local _sets, album_refresh_err = refresh_album_cache_for_export(extra_data.api_key, extra_data.api_secret,
      extra_data.account, { use_cache = true })
    if album_refresh_err then
      dt.print(string.format(_("Flickr: could not refresh albums before export: %s"), tostring(album_refresh_err)))
      dt.print_log(string.format("[dtrmflickr] initialize: album refresh failed: %s", tostring(album_refresh_err)))
    end
  end
  extra_data.album = current_album()
  dt.print_log(string.format("[dtrmflickr] initialize: %d image(s), transport=%s, %s",
    #images, TRANSPORT, extra_data.account and ("nsid=" .. tostring(extra_data.account.nsid)) or "NOT logged in"))
  return nil
end

local function split_filter_list(value)
  local filters = {}
  for item in tostring(value or ""):gmatch("[^,]+") do
    item = item:match("^%s*(.-)%s*$")
    if item ~= "" and item ~= EMPTY_FILTER_PREF then filters[#filters + 1] = item:lower() end
  end
  return filters
end

local function read_keyword_rules(prefix, values)
  local rules = {}
  for _, item in ipairs(values) do
    local filters = split_filter_list(dt.preferences.read(PLUGIN, prefix .. "_" .. item.key, "string"))
    for _, filter in ipairs(filters) do
      rules[#rules + 1] = { filter = filter, value = item }
    end
  end
  return rules
end

local function keyword_rule_matches(tag_names, rules)
  local matches = {}
  for _, rule in ipairs(rules or {}) do
    for _, tag_name in ipairs(tag_names or {}) do
      if metadata.tag_matches_filter(tag_name, rule.filter) then
        matches[#matches + 1] = { value = rule.value, filter = rule.filter, tag = tag_name }
        break
      end
    end
  end
  return matches
end

local function first_keyword_rule_match(tag_names, rules)
  local matches = keyword_rule_matches(tag_names, rules)
  return matches[1] and matches[1].value or nil
end

local function keyword_rule_filters()
  local filters = split_filter_list(dt.preferences.read(PLUGIN, "exclude_keyword_filters", "string"))
  for _, filter in ipairs(split_filter_list(dt.preferences.read(PLUGIN, "skip_upload_keyword_filters", "string"))) do
    filters[#filters + 1] = filter
  end
  local groups = {
    { prefix = "keyword_privacy", values = privacy_values },
    { prefix = "keyword_safety", values = safety_values },
    { prefix = "keyword_content_type", values = content_type_values },
    { prefix = "keyword_license", values = license_values },
  }
  for _, group in ipairs(groups) do
    for _, rule in ipairs(read_keyword_rules(group.prefix, group.values)) do
      filters[#filters + 1] = rule.filter
    end
  end
  return filters
end

local function first_matching_keyword_filter(tag_names, filters)
  for _, filter in ipairs(filters or {}) do
    for _, tag_name in ipairs(tag_names or {}) do
      if metadata.tag_matches_filter(tag_name, filter) then
        return filter, tag_name
      end
    end
  end
  return nil, nil
end

local privacy_restrictiveness = {
  public = 1,
  ["friends & family"] = 2,
  friends = 3,
  family = 3,
  private = 4,
}

local function choose_keyword_match(kind, matches)
  if #matches == 0 then return nil, nil end
  local chosen = matches[1].value
  if kind == "privacy" then
    for i = 2, #matches do
      local candidate = matches[i].value
      if (privacy_restrictiveness[candidate.pref] or 0) > (privacy_restrictiveness[chosen.pref] or 0) then
        chosen = candidate
      end
    end
  elseif kind == "safety" then
    for i = 2, #matches do
      local candidate = matches[i].value
      if (candidate.flickr_value or 0) > (chosen.flickr_value or 0) then
        chosen = candidate
      end
    end
  end

  local seen = {}
  local values = {}
  local filters = {}
  local tags = {}
  local has_conflict = false
  for _, match in ipairs(matches) do
    local pref = tostring(match.value.pref or "")
    if not seen[pref] then
      seen[pref] = true
      values[#values + 1] = pref
      if pref ~= chosen.pref then has_conflict = true end
    end
    if match.filter and match.filter ~= "" then filters[match.filter] = true end
    if match.tag and match.tag ~= "" then tags[match.tag] = true end
  end
  if #values < 2 or not has_conflict then return chosen, nil end

  local filter_list = {}
  for filter in pairs(filters) do filter_list[#filter_list + 1] = filter end
  table.sort(filter_list)
  local tag_list = {}
  for tag in pairs(tags) do tag_list[#tag_list + 1] = tag end
  table.sort(tag_list)

  return chosen, {
    kind = kind,
    values = values,
    used = chosen.pref,
    filters = table.concat(filter_list, ", "),
    tags = table.concat(tag_list, ", "),
  }
end

local function record_keyword_conflict(extra_data, conflict)
  if not extra_data or not conflict then return end
  extra_data.keyword_conflicts = extra_data.keyword_conflicts or {}
  extra_data.keyword_conflict_seen = extra_data.keyword_conflict_seen or {}
  local key = table.concat({ conflict.kind or "", conflict.used or "", conflict.filters or "", conflict.tags or "" }, "|")
  if extra_data.keyword_conflict_seen[key] then return end
  extra_data.keyword_conflict_seen[key] = true
  extra_data.keyword_conflicts[#extra_data.keyword_conflicts + 1] = conflict
  local msg = _("Flickr: keyword rule conflicts found; using safest/first matching rule")
  if not extra_data.keyword_conflict_toast_shown then
    if dt.print_toast then dt.print_toast(msg) else dt.print(msg) end
    extra_data.keyword_conflict_toast_shown = true
  end
end

local function format_keyword_conflict(conflict)
  local where = conflict.tags ~= "" and conflict.tags or conflict.filters
  return string.format(_("Flickr keyword conflict: %s '%s' matched %s; used %s"),
    conflict.kind or "rule", where or "?", table.concat(conflict.values or {}, ", "), conflict.used or "?")
end

local function apply_keyword_overrides(tag_names, privacy, safety, content_type, license)
  local privacy_match, privacy_conflict = choose_keyword_match("privacy",
    keyword_rule_matches(tag_names, read_keyword_rules("keyword_privacy", privacy_values)))
  local safety_match, safety_conflict = choose_keyword_match("safety",
    keyword_rule_matches(tag_names, read_keyword_rules("keyword_safety", safety_values)))
  local content_type_match, content_type_conflict = choose_keyword_match("content type",
    keyword_rule_matches(tag_names, read_keyword_rules("keyword_content_type", content_type_values)))
  local license_match, license_conflict = choose_keyword_match("license",
    keyword_rule_matches(tag_names, read_keyword_rules("keyword_license", license_values)))
  local conflicts = {}
  if privacy_conflict then conflicts[#conflicts + 1] = privacy_conflict end
  if safety_conflict then conflicts[#conflicts + 1] = safety_conflict end
  if content_type_conflict then conflicts[#conflicts + 1] = content_type_conflict end
  if license_conflict then conflicts[#conflicts + 1] = license_conflict end
  return
    privacy_match or privacy,
    safety_match or safety,
    content_type_match or content_type,
    license_match or license,
    {
      privacy = privacy_match ~= nil,
      safety = safety_match ~= nil,
      content_type = content_type_match ~= nil,
      license = license_match ~= nil,
    },
    conflicts
end

local function image_keyword_tags(image, tag_names)
  return metadata.image_keyword_tags(image, keyword_rule_filters(), tag_names, { max_tags = FLICKR_TAG_LIMIT })
end

local function should_skip_upload_by_keyword(tag_names)
  return first_matching_keyword_filter(tag_names,
    split_filter_list(dt.preferences.read(PLUGIN, "skip_upload_keyword_filters", "string")))
end

local function record_tag_limit_warning(extra_data, image, truncated_count)
  if not extra_data or not truncated_count or truncated_count <= 0 then return end
  extra_data.tag_limit_warnings = extra_data.tag_limit_warnings or {}
  extra_data.tag_limit_warnings[#extra_data.tag_limit_warnings + 1] = {
    image = image,
    truncated_count = truncated_count,
  }
  dt.print(string.format(_("Flickr: %s has more than %d publishable keywords; skipped %d extra tag(s)"),
    image and image.filename or "image", FLICKR_TAG_LIMIT, truncated_count))
end

local function record_post_error(extra_data, image, photo_id, action, err)
  extra_data.post_errors = extra_data.post_errors or {}
  extra_data.post_errors[#extra_data.post_errors + 1] = {
    image = image, photo_id = photo_id, error = err, action = action,
  }
  dt.print(string.format(_("Flickr: uploaded %s, but %s update failed: %s"),
    image.filename or "image", action, tostring(err)))
  dt.print_log(string.format("[dtrmflickr] store: %s update failed photo_id=%s: %s",
    action, tostring(photo_id), tostring(err)))
end

local function store(storage, image, format, filename, number, total, high_quality, extra_data)
  if not extra_data.account then
    local err = _("not logged in to Flickr")
    extra_data.failed[#extra_data.failed + 1] = { image = image, filename = filename, error = err }
    dt.print(_("Flickr upload skipped: ") .. err)
    dt.print_log("[dtrmflickr] store: skipped, no account")
    return
  end
  if not extra_data.api_key or not extra_data.api_secret then
    local err = _("missing Flickr API key/secret")
    extra_data.failed[#extra_data.failed + 1] = { image = image, filename = filename, error = err }
    dt.print(_("Flickr upload skipped: ") .. err)
    dt.print_log("[dtrmflickr] store: skipped, missing API credentials")
    return
  end

  local privacy = extra_data.privacy or current_privacy()
  local safety = extra_data.safety or current_safety()
  local content_type = extra_data.content_type or current_content_type()
  local license = extra_data.license or current_license()
  local permissions = extra_data.permissions or current_permissions()
  local sync = extra_data.sync or current_sync_fields()
  local tag_names = metadata.image_tag_names(image)
  local skip_filter, skip_tag = should_skip_upload_by_keyword(tag_names)
  if skip_filter then
    extra_data.skipped = extra_data.skipped or {}
    extra_data.skipped[#extra_data.skipped + 1] = {
      image = image,
      filename = filename,
      filter = skip_filter,
      tag = skip_tag,
    }
    dt.print(string.format(_("Flickr: skipped %s because keyword '%s' matched skip-upload rule '%s'"),
      image and image.filename or "image", tostring(skip_tag or ""), tostring(skip_filter or "")))
    dt.print_log(string.format("[dtrmflickr] store: skipped by keyword file='%s' tag='%s' filter='%s'",
      tostring(filename), tostring(skip_tag or ""), tostring(skip_filter or "")))
    return
  end
  local forced, conflicts
  privacy, safety, content_type, license, forced, conflicts = apply_keyword_overrides(tag_names, privacy, safety, content_type, license)
  for _, conflict in ipairs(conflicts or {}) do record_keyword_conflict(extra_data, conflict) end
  local tags, truncated_tags = nil, 0
  if sync.tags then
    tags, truncated_tags = image_keyword_tags(image)
    record_tag_limit_warning(extra_data, image, truncated_tags)
  end
  dt.print(string.format(_("Flickr: uploading %d/%d — %s"), number, total, image.filename or "?"))
  local photo_id, err = upload.upload_photo(extra_data.api_key, extra_data.api_secret, extra_data.account, filename, {
    title = sync.title and metadata.image_title(image, filename) or nil,
    description = sync.description and image and image.description or nil,
    tags = tags,
    is_public = (sync.privacy or forced.privacy) and privacy.is_public or nil,
    is_friend = (sync.privacy or forced.privacy) and privacy.is_friend or nil,
    is_family = (sync.privacy or forced.privacy) and privacy.is_family or nil,
    safety_level = (sync.safety or forced.safety) and safety.flickr_value or nil,
    content_type = (sync.content_type or forced.content_type) and content_type.flickr_value or nil,
    perm_comment = sync.permissions and permissions.perm_comment or nil,
    perm_addmeta = sync.permissions and permissions.perm_addmeta or nil,
  })
  if photo_id then
    state.set_photo_id(image, extra_data.account.nsid, photo_id)
    if sync.license or forced.license then
      local license_ok, license_err = rest.photos_licenses_set_license(extra_data.api_key, extra_data.api_secret,
        extra_data.account, photo_id, license.flickr_value)
      if not license_ok then
        record_post_error(extra_data, image, photo_id, "license", license_err)
      end
    end

    local date_taken = sync.date_taken and metadata.image_date_taken(image) or nil
    if date_taken then
      local dates_ok, dates_err = rest.photos_set_dates(extra_data.api_key, extra_data.api_secret,
        extra_data.account, photo_id, date_taken, 0)
      if not dates_ok then record_post_error(extra_data, image, photo_id, "date", dates_err) end
    end

    local lat, lon = nil, nil
    if sync.gps then lat, lon = metadata.image_location(image) end
    if lat and lon then
      local geo_ok, geo_err = rest.photos_geo_set_location(extra_data.api_key, extra_data.api_secret,
        extra_data.account, photo_id, lat, lon, 16)
      if not geo_ok then record_post_error(extra_data, image, photo_id, "location", geo_err) end
    end
    extra_data.uploaded[#extra_data.uploaded + 1] = { image = image, filename = filename, photo_id = photo_id }
    dt.print(string.format(_("Flickr: uploaded %s as photo %s"), image.filename or "image", photo_id))
    dt.print_log(string.format("[dtrmflickr] store: uploaded '%s' -> photo_id=%s", filename, photo_id))
  else
    extra_data.failed[#extra_data.failed + 1] = { image = image, filename = filename, error = err }
    dt.print(string.format(_("Flickr: upload failed for %s: %s"), image.filename or "image", tostring(err)))
    dt.print_log(string.format("[dtrmflickr] store: upload failed for '%s': %s", filename, tostring(err)))
  end
end

local function finalize(storage, image_table, extra_data)
  local total = 0
  for _img in pairs(image_table) do total = total + 1 end
  local uploaded = #(extra_data.uploaded or {})
  local failed = #(extra_data.failed or {})
  local skipped = #(extra_data.skipped or {})
  local post_errors = #(extra_data.post_errors or {})
  local keyword_conflicts = #(extra_data.keyword_conflicts or {})
  local tag_limit_warnings = #(extra_data.tag_limit_warnings or {})
  local album = extra_data.album or { mode = "none" }
  local album_errors = 0
  local photoset_id = album.photoset_id

  if uploaded > 0 and album.error then
    album_errors = album_errors + 1
    dt.print(string.format(_("Flickr: album not applied for '%s': %s"), tostring(album.query or ""), tostring(album.error)))
    dt.print_log(string.format("[dtrmflickr] finalize: album not applied query='%s': %s",
      tostring(album.query or ""), tostring(album.error)))
  end

  if uploaded > 0 and album.mode == "create" then
    local first = extra_data.uploaded[1]
    local created_id, err = rest.photosets_create(extra_data.api_key, extra_data.api_secret, extra_data.account,
      album.title, first.photo_id)
    photoset_id = created_id
    if photoset_id then
      state.add_set(first.image, extra_data.account.nsid, photoset_id)
      dt.print(string.format(_("Flickr: created album '%s'"), album.title))
      dt.print_log(string.format("[dtrmflickr] finalize: created photoset=%s title='%s'", photoset_id, album.title))
    else
      album_errors = album_errors + 1
      dt.print(string.format(_("Flickr: album create failed: %s"), tostring(err)))
      dt.print_log(string.format("[dtrmflickr] finalize: photoset create failed: %s", tostring(err)))
    end
  end

  if uploaded > 0 and album.duplicate_create and photoset_id and photoset_id ~= "" then
    dt.print(string.format(_("Flickr: album '%s' already exists; adding photos to existing album"), tostring(album.title or photoset_id)))
    dt.print_log(string.format("[dtrmflickr] finalize: create matched existing photoset=%s title='%s'",
      tostring(photoset_id), tostring(album.title or "")))
  end

  if uploaded > 0 and photoset_id and photoset_id ~= "" then
    local start = album.mode == "create" and 2 or 1
    for i = start, uploaded do
      local item = extra_data.uploaded[i]
      local ok, err = rest.photosets_add_photo(extra_data.api_key, extra_data.api_secret, extra_data.account,
        photoset_id, item.photo_id)
      if ok or photoset_add_is_already_present(err) then
        state.add_set(item.image, extra_data.account.nsid, photoset_id)
      else
        album_errors = album_errors + 1
        dt.print(string.format(_("Flickr: could not add photo %s to album: %s"), tostring(item.photo_id), tostring(err)))
        dt.print_log(string.format("[dtrmflickr] finalize: add photo_id=%s photoset=%s failed: %s",
          tostring(item.photo_id), tostring(photoset_id), tostring(err)))
      end
    end
  end

  for _, conflict in ipairs(extra_data.keyword_conflicts or {}) do
    dt.print(format_keyword_conflict(conflict))
  end

  dt.print(string.format(_("Flickr: finished — %d uploaded, %d skipped, %d failed, %d post-upload error(s), %d album error(s), %d total"),
    uploaded, skipped, failed, post_errors, album_errors, total))
  if keyword_conflicts > 0 then
    dt.print(string.format(_("Flickr: %d keyword rule conflict(s); see messages above"), keyword_conflicts))
  end
  if tag_limit_warnings > 0 then
    dt.print(string.format(_("Flickr: %d image(s) had keywords truncated to Flickr's %d-tag limit"),
      tag_limit_warnings, FLICKR_TAG_LIMIT))
  end
  dt.print_log(string.format("[dtrmflickr] finalize: uploaded=%d skipped=%d failed=%d post_errors=%d album_errors=%d keyword_conflicts=%d tag_limit_warnings=%d total=%d",
    uploaded, skipped, failed, post_errors, album_errors, keyword_conflicts, tag_limit_warnings, total))
end

----------------------------------------------------------------------
-- script_manager integration + registration.
----------------------------------------------------------------------
local script_data = {}
script_data.metadata = {
  name = "Flickr",
  purpose = _("export images to Flickr"),
  author = "dtrmflickr",
}
script_data.destroy_method = "hide"
local function destroy()
  dt.destroy_storage(STORAGE)
  if dt.destroy_event then dt.destroy_event(PLUGIN .. "_selection_changed", "selection-changed") end
  if dt.gui.libs and dt.gui.libs[PANEL] then dt.gui.libs[PANEL].visible = false end
end
local function restart()
  if dt.gui.libs and dt.gui.libs[PANEL] then
    dt.gui.libs[PANEL].visible = true
    refresh_panel(true, false)
  end
end
script_data.destroy = destroy
script_data.restart = restart
script_data.show = restart
script_data.__test = {
  save_token = save_token,
  load_token = load_token,
  clear_token = clear_token,
  pack_token = pack_token,
  unpack_token = unpack_token,
  json_object = json_object,
  json_string_field = json_string_field,
  current_album = current_album,
  album_label = album_label,
  set_album_cache = set_album_cache,
  find_album_match = find_album_match,
  sort_albums = sort_albums,
  ordered_set_ids = ordered_set_ids,
  refresh_album_cache_for_export = refresh_album_cache_for_export,
  current_safety = current_safety,
  current_content_type = current_content_type,
  current_license = current_license,
  image_tag_names = metadata.image_tag_names,
  apply_keyword_overrides = apply_keyword_overrides,
  format_keyword_conflict = format_keyword_conflict,
  image_keyword_tags = image_keyword_tags,
  image_date_taken = metadata.image_date_taken,
  image_location = metadata.image_location,
  refresh_panel = refresh_panel,
  parse_remote_tags = parse_remote_tags,
  parse_search_content_type = parse_search_content_type,
  parse_search_photos = claim.parse_search_photos,
  claim_match_terms = claim.claim_match_terms,
  choose_existing_match = claim.choose_existing_match,
  claim_existing_for_image = claim.claim_existing_for_image,
  parse_photo_id_or_url = parse_photo_id_or_url,
  panel_content_type_index_from_search_value = panel_content_type_index_from_search_value,
  privacy_values = privacy_values,
  safety_values = safety_values,
  content_type_values = content_type_values,
  license_values = license_values,
}

dt.register_storage(STORAGE, HUMAN, store, finalize, supported, initialize, storage_widget)
dt.register_lib(
  PANEL,
  HUMAN,
  true,
  false,
  { [dt.gui.views.lighttable] = { "DT_UI_CONTAINER_PANEL_RIGHT_CENTER", 80 } },
  panel_widget,
  function() refresh_panel(true, false) end,
  nil
)
dt.register_event(PLUGIN .. "_selection_changed", "selection-changed", function()
  refresh_panel(false, http.quiet_rest_available())
end)

refresh_status()
refresh_panel(false, http.quiet_rest_available())
dt.print_log("[dtrmflickr] registered Flickr export storage (step 3); " .. TRANSPORT_MSG)

return script_data
end

return require "dtrmflickr.dtrmflickr"
